{
  "results": [
    {
      "server": "rivetos",
      "tools": [
        {
          "tool_name": "rivetos__memory_browse",
          "description": "Browse RivetOS conversation messages chronologically. Unlike memory_search (which ranks by relevance), this returns messages in time order. Use to review what happened in a session, catch up on recent activity, or read a specific conversation by ID.",
          "score": 1.0,
          "input_schema": {
            "$schema": "http://json-schema.org/draft-07/schema#",
            "type": "object",
            "properties": {
              "conversation_id": {
                "description": "Browse a specific conversation by ID",
                "type": "string"
              },
              "since": {
                "description": "Show messages after this time (ISO timestamp, e.g. 2025-03-15T10:00:00Z)",
                "type": "string"
              },
              "before": {
                "description": "Show messages before this time (ISO timestamp, e.g. 2025-03-16)",
                "type": "string"
              },
              "agent": {
                "description": "Filter by agent (opus, grok, etc.)",
                "type": "string"
              },
              "limit": {
                "description": "Max messages to return (1–200, default: 50)",
                "type": "integer",
                "minimum": 1,
                "maximum": 200
              },
              "order": {
                "description": "Chronological order — asc (oldest first) or desc (newest first, default)",
                "type": "string",
                "enum": [
                  "asc",
                  "desc"
                ]
              }
            }
          }
        }
      ]
    }
  ],
  "total_hidden_tools": 51,
  "status": "ready",
  "note": null
}

